     2→using System;
     3→using System.Collections.Generic;
     4→using System.Net.Mime;
     5→using System.Text.Json;
     6→using System.Text.Json.Serialization;
     7→using System.Threading;
     8→using System.Threading.Tasks;
     9→using CanvasCraft.Domain.Exceptions;
    10→using CanvasCraft.Domain.Inferencing;
    11→using CanvasCraft.Domain.ModelRegistry;
    12→using CanvasCraft.Domain.Tracking;
    13→using Microsoft.AspNetCore.Http;
    14→using Microsoft.AspNetCore.Mvc;
    15→using Microsoft.Extensions.Logging;
    16→
    17→namespace CanvasCraft.Api.Controllers
    18→{
    19→    /// <summary>
    20→    ///     ReST controller responsible for runtime model serving.  
    21→    ///     Provides prediction, metadata lookup and live-reload endpoints.
    22→    /// </summary>
    23→    [ApiController]
    24→    [Route("api/serve")]
    25→    [Produces(MediaTypeNames.Application.Json)]
    26→    public sealed class ServingController : ControllerBase
    27→    {
    28→        private readonly IInferenceService _inferenceService;
    29→        private readonly ILogger<ServingController> _logger;
    30→        private readonly IModelRegistryService _modelRegistry;
    31→        private readonly IExperimentTrackingService _trackingService;
    32→
    33→        public ServingController(
    34→            IModelRegistryService modelRegistry,
    35→            IInferenceService inferenceService,
    36→            IExperimentTrackingService trackingService,
    37→            ILogger<ServingController> logger)
    38→        {
    39→            _modelRegistry = modelRegistry ?? throw new ArgumentNullException(nameof(modelRegistry));
    40→            _inferenceService = inferenceService ?? throw new ArgumentNullException(nameof(inferenceService));
    41→            _trackingService = trackingService ?? throw new ArgumentNullException(nameof(trackingService));
    42→            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
    43→        }
    44→
    45→        #region ---------- Prediction ---------------------------------------------------------------------------
    46→
    47→        /// <summary>
    48→        ///     Executes a prediction against the specified model version.
    49→        /// </summary>
    50→        /// <remarks>
    51→        ///     The request body must be a JSON dictionary whose keys map exactly to the model’s feature names.
    52→        /// </remarks>
    53→        /// <param name="modelName">Registered model name or alias.</param>
    54→        /// <param name="request">Input feature vector.</param>
    55→        /// <param name="ct">Cancellation token.</param>
    56→        /// <returns>Prediction result along with contextual metadata.</returns>
    57→        [HttpPost("{modelName}/predict")]
    58→        [Consumes(MediaTypeNames.Application.Json)]
    59→        [ProducesResponseType(typeof(PredictionResponseDto), StatusCodes.Status200OK)]
    60→        [ProducesResponseType(StatusCodes.Status400BadRequest)]
    61→        [ProducesResponseType(StatusCodes.Status404NotFound)]
    62→        [ProducesResponseType(StatusCodes.Status500InternalServerError)]
    63→        public async Task<IActionResult> PredictAsync(
    64→            [FromRoute] string modelName,
    65→            [FromBody] PredictionRequestDto request,
    66→            CancellationToken ct)
    67→        {
    68→            if (string.IsNullOrWhiteSpace(modelName))
    69→            {
    70→                return BadRequest("Model name must be provided.");
    71→            }
    72→
    73→            if (request?.Features is null || request.Features.Count == 0)
    74→            {
    75→                return BadRequest("Request payload must contain at least one feature.");
    76→            }
    77→
    78→            try
    79→            {
    80→                // 1) Obtain model manifest (metadata & location).
    81→                var manifest = await _modelRegistry.GetLatestModelAsync(modelName, ct);
    82→                if (manifest is null)
    83→                {
    84→                    return NotFound($"Model '{modelName}' does not exist in registry.");
    85→                }
    86→
    87→                // 2) Run inference.
    88→                var output = await _inferenceService.PredictAsync(
    89→                    manifest,
    90→                    request.Features,
    91→                    ct);
    92→
    93→                // 3) Persist prediction event for audit / feedback loop.
    94→                var predictionId = Guid.NewGuid().ToString("N");
    95→                await _trackingService.TrackPredictionAsync(
    96→                    new PredictionEvent
    97→                    {
    98→                        Id = predictionId,
    99→                        ModelId = manifest.Id,
   100→                        ModelVersion = manifest.Version,
   101→                        TimestampUtc = DateTime.UtcNow,
   102→                        Input = request.Features,
   103→                        Output = output
   104→                    }, ct);
   105→
   106→                // 4) Build response.
   107→                var response = new PredictionResponseDto
   108→                {
   109→                    PredictionId = predictionId,
   110→                    ModelName = manifest.Name,
   111→                    ModelVersion = manifest.Version,
   112→                    Timestamp = DateTime.UtcNow,
   113→                    Output = output
   114→                };
   115→
   116→                return Ok(response);
   117→            }
   118→            catch (ModelRegistryException ex)
   119→            {
   120→                _logger.LogWarning(ex, "Model registry failure for model {ModelName}.", modelName);
   121→                return NotFound(ex.Message);
   122→            }
   123→            catch (InferenceException ex)
   124→            {
   125→                _logger.LogError(ex, "Inference failure for model {ModelName}.", modelName);
   126→                return StatusCode(StatusCodes.Status500InternalServerError, "Inference engine error.");
   127→            }
   128→            catch (Exception ex)
   129→            {
   130→                _logger.LogCritical(ex, "Unhandled error during prediction for model {ModelName}.", modelName);
   131→                return StatusCode(StatusCodes.Status500InternalServerError, "Unhandled server error.");
   132→            }
   133→        }
   134→
   135→        #endregion
   136→
   137→        #region ---------- Metadata -----------------------------------------------------------------------------
   138→
   139→        /// <summary>
   140→        ///     Returns the metadata (manifest) for the latest version of a model.
   141→        /// </summary>
   142→        /// <param name="modelName">Registered model name.</param>
   143→        /// <param name="ct">Cancellation token.</param>
   144→        [HttpGet("{modelName}/metadata")]
   145→        [ProducesResponseType(typeof(ModelManifest), StatusCodes.Status200OK)]
   146→        [ProducesResponseType(StatusCodes.Status404NotFound)]
   147→        public async Task<IActionResult> GetMetadataAsync(
   148→            [FromRoute] string modelName,
   149→            CancellationToken ct)
   150→        {
   151→            try
   152→            {
   153→                var manifest = await _modelRegistry.GetLatestModelAsync(modelName, ct);
   154→                if (manifest is null) return NotFound();
   155→
   156→                return Ok(manifest);
   157→            }
   158→            catch (ModelRegistryException ex)
   159→            {
   160→                _logger.LogWarning(ex, "Model registry failure for model {ModelName}.", modelName);
   161→                return NotFound(ex.Message);
   162→            }
   163→        }
   164→
   165→        #endregion
   166→
   167→        #region ---------- Hot Reload ---------------------------------------------------------------------------
