    29→    {
    30→        // ─────────────────────────────────────────────────────────────────────────────
    31→        // Fields
    32→        // ─────────────────────────────────────────────────────────────────────────────
    33→        private readonly ConcurrentDictionary<IObserver<ServingEventBase>, byte> _observers;
