    62→    public abstract class PipelineStepBase : IPipelineStep
    63→    {
    64→        private readonly ILogger _logger;
    65→        private StepStatus _status = StepStatus.Pending;
    66→
    67→        protected PipelineStepBase(ILogger logger) => _logger = logger;
    68→
    69→        public abstract string Name { get; }
    70→
    71→        public StepStatus Status
    72→        {
    73→            get => _status;
    74→            protected set
    75→            {
    76→                if (_status == value) return;
    77→                _status = value;
    78→                StatusChanged?.Invoke(this, new PipelineStepStatusChangedEventArgs(Name, value, DateTimeOffset.UtcNow));
    79→            }
    80→        }
    81→
    82→        public event EventHandler<PipelineStepStatusChangedEventArgs>? StatusChanged;
    83→
    84→        public async Task<PipelineContext> ExecuteAsync(PipelineContext context, CancellationToken token = default)
    85→        {
    86→            try
    87→            {
    88→                Status = StepStatus.Running;
    89→                _logger.LogInformation("Step '{Step}' started.", Name);
    90→
    91→                var result = await ExecuteCoreAsync(context, token).ConfigureAwait(false);
    92→
    93→                Status = StepStatus.Succeeded;
    94→                _logger.LogInformation("Step '{Step}' succeeded.", Name);
    95→                return result;
    96→            }
    97→            catch (Exception ex)
    98→            {
    99→                Status = StepStatus.Failed;
   100→                _logger.LogError(ex, "Step '{Step}' failed.", Name);
   101→                throw; // bubble up; pipeline orchestrator decides fate
   102→            }
   103→        }
